sql:
SELECT COUNT(*)
FROM dma_channels
WHERE priority > 10;

SELECT channel_id
FROM dma_channels
WHERE priority > 10;

external_knowledge:
- The priority level indicates the importance of a DMA channel within a project;
- Channels with higher priority values are considered more important;
- "Top-priority descriptions" refer to the descriptions of DMA channels that have the highest priority among their peers in the same project.

sql:
SELECT dma_controller, COUNT(channel_id) AS total_channels
FROM dma_channels
GROUP BY dma_controller;

SELECT channel_id
FROM dma_channels
WHERE priority = (SELECT MAX(priority) FROM dma_channels);

SELECT COUNT(*) AS active_project_channels
FROM project_dma_configs
WHERE config_status = 'active';

external_knowledge:
- 'captains' refers to users with the role of 'project manager';
- 'anchors' symbolize DMA channels;
- 'weight of the anchors' corresponds to the priority levels of the DMA channels.

sql:
SELECT AVG(new_priority) AS average_priority
FROM configuration_history
WHERE modification_date > '2023-01-01';
